const item = $input.first().json?.body || $input.first().json;
const required = ['payment_intent_id', 'customer_email', 'order_notes'];
const missing = required.filter(f => !item[f]);
if (missing.length > 0) throw new Error(`Missing required fields: ${missing.join(', ')}`);
const email = (item.customer_email || '').trim().toLowerCase();
if (!email.includes('@')) throw new Error('Invalid customer_email format');
const orderRef = item.order_ref || `ORD-${Date.now()}`;
return [{ json: {
  payment_intent_id:  item.payment_intent_id.trim(),
  customer_email:     email,
  customer_name:      item.customer_name || '',
  customer_phone:     item.customer_phone || '',
  order_notes:        item.order_notes || '',
  service_type:       item.service_type || 'general',
  collection_address: item.collection_address || '',
  postcode:           (item.postcode || '').trim().toUpperCase(),
  requested_date:     item.requested_date || '',
  order_value_gbp:    parseFloat(item.order_value_gbp) || 0,
  order_ref:          orderRef,
  received_at:        new Date().toISOString()
}}];

const rows = $input.all();
const order = $('Validate & Parse Order').first().json;
const payment = rows[0]?.json || {};
const status = payment.status || 'error';
const amountPence = payment.amount || 0;
return [{ json: {
  ...order,
  payment_status:      status,
  payment_valid:       status === 'succeeded',
  payment_amount_gbp:  amountPence / 100,
  payment_currency:    payment.currency || 'gbp',
  stripe_customer_id:  payment.customer || null,
  payment_error:       payment.last_payment_error?.message || null
}}];

