parameters.jsCode:
const rows = $input.all();
const order = $('Validate & Parse Order').first().json;
const payment = $('Consolidate Payment Result').first().json;
const aiOutput = $('Extract Order Details').first().json.output || {};
const contact = rows[0]?.json?.contact || rows[0]?.json || {};
return [{ json: {
  ...order,
  payment_amount_gbp:   payment.payment_amount_gbp,
  stripe_customer_id:   payment.stripe_customer_id,
  extracted:            aiOutput,
  contact_id:           String(contact.id || contact.contact?.id || ''),
  customer_name:        aiOutput.customer_name || order.customer_name,
  customer_email:       aiOutput.customer_email || order.customer_email,
  customer_phone:       aiOutput.customer_phone || order.customer_phone,
  collection_address:   aiOutput.collection_address || order.collection_address,
  postcode:             aiOutput.postcode || order.postcode,
  waste_type:           aiOutput.waste_type || 'general',
  skip_size:            aiOutput.skip_size || '',
  priority:             aiOutput.priority || 'standard',
  special_instructions: aiOutput.special_instructions || '',
  access_restrictions:  aiOutput.access_restrictions || ''
}}];

const rows = $input.all();
const ctx = $('Consolidate Contact').first().json;
const deal = rows[0]?.json || {};
const dealId = String(deal.id || deal.deal?.id || '');
return [{ json: {
  ...ctx,
  deal_id:   dealId,
  deal_name: deal.name || deal.deal?.name || ctx.order_ref
}}];

const rows = $input.all();
const ctx = $('Consolidate Deal').first().json;
const suppliers = rows.filter(r => !r.json.error && r.json.id);
if (suppliers.length === 0) {
  // No supplier found — flag for manual assignment
  return [{ json: {
    ...ctx,
    supplier_id:    null,
    supplier_email: null,
    supplier_name:  'UNASSIGNED',
    supplier_phone: null,
    supplier_found: false,
    all_supplier_ids: []
  }}];
}
const primary = suppliers[0].json;
const allIds = suppliers.map(s => String(s.json.id));
return [{ json: {
  ...ctx,
  supplier_id:      String(primary.id),
  supplier_email:   primary.email,
  supplier_name:    `${primary.first_name || ''} ${primary.last_name || ''}`.trim(),
  supplier_phone:   primary.mobile_number || primary.phone || '',
  supplier_found:   true,
  all_supplier_ids: allIds
}}];

const rows = $input.all();
const ctx = $('Consolidate Supplier').first().json;
const deal = rows[0]?.json || {};
const stageName = (deal.deal_stage?.name || deal.stage_name || '').toLowerCase();
const acceptedStages = ['accepted', 'confirmed', 'partner confirmed', 'supplier accepted', 'in progress'];
const isAccepted = acceptedStages.some(s => stageName.includes(s));
return [{ json: {
  ...ctx,
  current_deal_stage:  stageName,
  supplier_accepted:   isAccepted,
  sla_check_at:        new Date().toISOString(),
  sla_attempt:         1
}}];

