parameters.jsCode:
const rows = $input.all();
const ctx = $('Consolidate SLA Status').first().json;
const firstSupplierId = ctx.supplier_id;
// Skip the first supplier who already failed to respond
const available = rows.filter(r => !r.json.error && r.json.id && String(r.json.id) !== firstSupplierId);
if (available.length === 0) {
  return [{ json: {
    ...ctx,
    next_supplier_id:    null,
    next_supplier_email: null,
    next_supplier_name:  'NONE AVAILABLE',
    next_supplier_found: false
  }}];
}
const next = available[0].json;
return [{ json: {
  ...ctx,
  next_supplier_id:    String(next.id),
  next_supplier_email: next.email,
  next_supplier_name:  `${next.first_name || ''} ${next.last_name || ''}`.trim(),
  next_supplier_phone: next.mobile_number || next.phone || '',
  next_supplier_found: true
}}];

const rows = $input.all();
const ctx = $('Consolidate Next Supplier').first().json;
const deal = rows[0]?.json || {};
const stageName = (deal.deal_stage?.name || deal.stage_name || '').toLowerCase();
const acceptedStages = ['accepted', 'confirmed', 'partner confirmed', 'supplier accepted', 'in progress'];
const isAccepted = acceptedStages.some(s => stageName.includes(s));
return [{ json: {
  ...ctx,
  retry_deal_stage:  stageName,
  retry_accepted:    isAccepted,
  retry_check_at:    new Date().toISOString(),
  sla_attempt:       2
}}];

